        code2=re.sub(r'(<h2 style="margin:0;font-size:18px;color:#111;text-transform:uppercase;font-weight:800;">Product Overview</h2></td></tr><tr><td style="padding-top:18px;">)(.*?)(</td></tr></tbody></table><table style="margin-bottom:34px;" border="0" width="100%" cellspacing="0" cellpadding="0"><tbody><tr><td style="border-left:5px solid #111;padding-left:15px;padding-bottom:12px;"><h2 style="margin:0;font-size:18px;color:#111;text-transform:uppercase;font-weight:800;">Key Features and Advantages</h2>)', r'\1'+repl+r'\3', code, flags=re.S)
        r['代码']=code2
